/**
 * Conversa-alerta: edite o fallback ou defina CHATWOOT_ALERT_CONVERSATION_ID no ambiente (self-hosted).
 */
const CONVERSATION_ID =
  (typeof process !== 'undefined' && process.env && process.env.CHATWOOT_ALERT_CONVERSATION_ID)
    ? String(process.env.CHATWOOT_ALERT_CONVERSATION_ID)
    : 'SUBSTITUIR_ID_CONVERSA';

const ACCOUNT_ID = 1;
const BASE_URL = 'https://chat.stratostech.com.br';

const item = $input.first().json;
const wf = item.workflow || {};
const err = item.error || (item.execution && item.execution.error) || {};
const exec = item.execution || {};

const nodeName = (err.node && err.node.name) ? err.node.name : '';
const errMsg = err.message || err.description || JSON.stringify(err || {});
const stack = err.stack ? String(err.stack).slice(0, 2500) : '';

const lines = [
  '🚨 *Erro em workflow n8n*',
  '',
  `*Workflow:* ${wf.name || '(sem nome)'} (${wf.id || '-'})`,
  `*Execução:* ${exec.id || '-'}`,
];

if (nodeName) {
  lines.push(`*Nó:* ${nodeName}`);
}

lines.push('', '*Erro:*', String(errMsg));

if (stack) {
  lines.push('', '*Stack:*', stack);
}

const content = lines.join('\n');

return [{
  json: {
    baseUrl: BASE_URL,
    accountId: ACCOUNT_ID,
    conversationId: CONVERSATION_ID,
    content,
  },
}];
